sql:
SELECT AVG(w.thickness) AS average_thickness
FROM walls w
INNER JOIN wall_repairs wr ON w.wall_id = wr.wall_id;

SELECT MAX(thickness) AS max_wall_thickness
FROM walls
WHERE building_id = 1;

SELECT wall_id, AVG(length) AS average_breadth
FROM walls
GROUP BY wall_id;

SELECT orientation, SUM(length) AS total_length
FROM walls
GROUP BY orientation;

